76	// beadAutoCommit commits .ddx/beads.jsonl when configured by git.auto_commit.
77	// The operation string describes what happened (e.g. "create ddx-abc123").
78	// When a commit lands, the resulting SHA is returned.
79	func (f *CommandFactory) beadAutoCommit(operation string) (string, error) {
80		return f.beadAutoCommitWithMode(operation, false)
81	}
