91	func (f *CommandFactory) beadAutoCommitWithMode(operation string, includeStaged bool) (string, error) {
92		workspaceRoot := f.beadWorkspaceRoot()
93		if workspaceRoot == "" {
94			workspaceRoot = f.WorkingDir
95		}
96		beadsFile := filepath.Join(workspaceRoot, ".ddx", "beads.jsonl")
97		return f.beadAutoCommitPathsWithMode(operation, []string{beadsFile}, includeStaged)
98	}
