100	func (f *CommandFactory) beadAutoCommitPathsWithMode(operation string, paths []string, includeStaged bool) (string, error) {
101		workspaceRoot := f.beadWorkspaceRoot()
102		if workspaceRoot == "" {
103			workspaceRoot = f.WorkingDir
104		}
105	
106		cfg, err := config.LoadWithWorkingDir(workspaceRoot)
107		if err != nil {
108			return "", fmt.Errorf("load config for bead auto-commit: %w", err)
109		}
110		if cfg.Git == nil {
111			return "", nil
112		}
113		acCfg := gitpkg.AutoCommitConfig{
114			AutoCommit:    cfg.Git.AutoCommit,
115			CommitPrefix:  cfg.Git.CommitPrefix,
116			IncludeStaged: includeStaged,
117		}
118		sha, err := gitpkg.AutoCommitFiles(paths, "beads", operation, acCfg)
119		if err != nil {
120			return "", fmt.Errorf("auto-commit beads tracker after %s: %w", operation, err)
121		}
122		return sha, nil
123	}
