211	func isReviewCloseBead(b *bead.Bead) bool {
212		if b == nil {
213			return false
214		}
215		for _, label := range b.Labels {
216			switch label {
217			case "action:review", "kind:review", "phase:review", "review-finding":
218				return true
219			}
220		}
221		return false
