224	func (f *CommandFactory) beadWorkspaceRoot() string {
225		dir := os.Getenv("DDX_BEAD_DIR")
226		if dir != "" {
227			if filepath.Base(dir) == ".ddx" {
228				if !filepath.IsAbs(dir) && f.WorkingDir != "" {
229					if workspaceRoot := gitpkg.FindNearestDDxWorkspace(f.WorkingDir); workspaceRoot != "" {
230						return workspaceRoot
231					}
232					dir = filepath.Join(f.WorkingDir, dir)
233				}
234				return filepath.Dir(dir)
235			}
236			if !filepath.IsAbs(dir) && f.WorkingDir != "" {
237				return filepath.Join(f.WorkingDir, dir)
238			}
239			return dir
240		}
241		if f.WorkingDir == "" {
242			return ""
243		}
244		if workspaceRoot := gitpkg.FindNearestDDxWorkspace(f.WorkingDir); workspaceRoot != "" {
245			return workspaceRoot
246		}
247		return f.WorkingDir
248	}
