359	func (f *CommandFactory) newBeadShowCommand() *cobra.Command {
360		cmd := &cobra.Command{
361			Use:   "show <id>",
362			Short: "Show a bead",
363			Args:  cobra.ExactArgs(1),
364			RunE: func(cmd *cobra.Command, args []string) error {
365				s := f.beadStore()
366				b, err := s.GetWithArchive(args[0])
367				if err != nil {
368					return err
369				}
370	
371				asJSON, _ := cmd.Flags().GetBool("json")
372				if asJSON {
373					// Externalized events live in a sidecar; inline them for the
374					// JSON view so consumers (and the `events` UI projection)
375					// see a single uniform shape.
376					if err := s.LoadEventsInline(b); err != nil {
377						return err
378					}
379					data, err := bead.MarshalBead(*b)
380					if err != nil {
381						return err
382					}
383					var obj map[string]any
384					if err := json.Unmarshal(data, &obj); err != nil {
385						return err
386					}
387					workspaceRoot := f.beadWorkspaceRoot()
388					if workspaceRoot == "" {
389						workspaceRoot = f.WorkingDir
390					}
391					metrics, err := beadMetricsFor(workspaceRoot, b.ID)
392					if err != nil {
393						return err
394					}
395					if metrics == nil {
396						metrics = &beadMetricsSummary{}
397					}
398					obj["metrics"] = metrics
399					enc := json.NewEncoder(cmd.OutOrStdout())
400					enc.SetIndent("", "  ")
401					return enc.Encode(obj)
402				}
403	
404				out := cmd.OutOrStdout()
405				fmt.Fprintf(out, "ID:       %s\n", b.ID)
406				fmt.Fprintf(out, "Title:    %s\n", b.Title)
407				fmt.Fprintf(out, "Type:     %s\n", b.IssueType)
408				fmt.Fprintf(out, "Status:   %s\n", b.Status)
409				fmt.Fprintf(out, "Priority: %d\n", b.Priority)
410				if len(b.Labels) > 0 {
411					fmt.Fprintf(out, "Labels:   %s\n", strings.Join(b.Labels, ", "))
412				}
413				if b.Owner != "" {
414					fmt.Fprintf(out, "Owner:    %s\n", b.Owner)
415				}
416				if b.Parent != "" {
417					fmt.Fprintf(out, "Parent:   %s\n", b.Parent)
418				}
419				if len(b.Dependencies) > 0 {
420					fmt.Fprintf(out, "Deps:     %s\n", strings.Join(b.DepIDs(), ", "))
421				}
422				if b.Description != "" {
423					fmt.Fprintf(out, "Desc:     %s\n", b.Description)
424				}
425				if b.Acceptance != "" {
426					fmt.Fprintf(out, "Accept:   %s\n", b.Acceptance)
427				}
428				fmt.Fprintf(out, "Created:  %s\n", b.CreatedAt.Format("2006-01-02 15:04:05"))
429				fmt.Fprintf(out, "Updated:  %s\n", b.UpdatedAt.Format("2006-01-02 15:04:05"))
430				// Show agent session evidence if present
431				if b.Extra != nil {
432					if sessionID, ok := b.Extra["session_id"]; ok && sessionID != "" {
433						fmt.Fprintf(out, "Session:  %v\n", sessionID)
434						// Try to resolve session details
435						if sess := f.resolveAgentSession(fmt.Sprint(sessionID)); sess != nil {
436							fmt.Fprintf(out, "Harness:  %s\n", sess.Harness)
437							if sess.Model != "" {
438								fmt.Fprintf(out, "Model:    %s\n", sess.Model)
439							}
440							if sess.Tokens > 0 {
441								fmt.Fprintf(out, "Tokens:   %d (in: %d, out: %d)\n", sess.Tokens, sess.InputTokens, sess.OutputTokens)
442							}
443							if sess.CostUSD > 0 {
444								fmt.Fprintf(out, "Cost:     $%.4f\n", sess.CostUSD)
445							}
446							if sess.Duration > 0 {
447								fmt.Fprintf(out, "Duration: %dms\n", sess.Duration)
448							}
449						}
450					}
451					if commitSHA, ok := b.Extra["closing_commit_sha"]; ok && commitSHA != "" {
452						fmt.Fprintf(out, "Commit:   %v\n", commitSHA)
453					}
454					if v, ok := b.Extra["claimed-at"]; ok {
455						fmt.Fprintf(out, "Claimed:  %v\n", v)
456					}
457					if v, ok := b.Extra["claimed-machine"]; ok {
458						fmt.Fprintf(out, "Machine:  %v\n", v)
459					}
460					if v, ok := b.Extra["claimed-session"]; ok {
461						fmt.Fprintf(out, "Session:  %v\n", v)
462					}
463					if v, ok := b.Extra["claimed-worktree"]; ok {
464						fmt.Fprintf(out, "Worktree: %v\n", v)
465					}
466				}
467				claimKeys := map[string]bool{
468					"claimed-at": true, "claimed-pid": true,
469					"claimed-machine": true, "claimed-session": true, "claimed-worktree": true,
470					"session_id": true, "closing_commit_sha": true,
471				}
472				for k, v := range b.Extra {
473					if !claimKeys[k] {
474						fmt.Fprintf(out, "%s: %v\n", k, v)
475					}
476				}
477				return nil
478			},
479		}
480		cmd.Flags().Bool("json", false, "Output as JSON")
481		return cmd
482	}
