484	func (f *CommandFactory) newBeadUpdateCommand() *cobra.Command {
485		cmd := &cobra.Command{
486			Use:   "update <id>",
487			Short: "Update a bead",
488			Args:  cobra.ExactArgs(1),
489			RunE: func(cmd *cobra.Command, args []string) error {
490				if err := f.checkLifecycleMigrationGate(cmd); err != nil {
491					return err
492				}
493				s := f.beadStore()
494	
495				// --claim and --unclaim use dedicated store methods
496				if claim, _ := cmd.Flags().GetBool("claim"); claim {
497					assignee, _ := cmd.Flags().GetString("assignee")
498					if assignee == "" {
499						assignee = resolveClaimAssignee()
500					}
501					if err := s.Claim(args[0], assignee); err != nil {
502						return err
503					}
504					if _, err := f.beadAutoCommit("claim " + args[0]); err != nil {
505						return err
506					}
507					return nil
508				}
509				if unclaim, _ := cmd.Flags().GetBool("unclaim"); unclaim {
510					if err := s.Unclaim(args[0]); err != nil {
511						return err
512					}
513					if _, err := f.beadAutoCommit("unclaim " + args[0]); err != nil {
514						return err
515					}
516					return nil
517				}
518	
519				if unsetFlags, _ := cmd.Flags().GetStringArray("unset"); len(unsetFlags) > 0 {
520					for _, key := range unsetFlags {
521						if isProtectedBeadExtraKey(key) {
522							return fmt.Errorf("cannot unset protected bead field: %s", key)
523						}
524					}
525				}
526	
527				var setFlags []string
528				if rawSetFlags, _ := cmd.Flags().GetStringArray("set"); len(rawSetFlags) > 0 {
529					setFlags = make([]string, 0, len(rawSetFlags))
530					for _, kv := range rawSetFlags {
531						k, v, ok := strings.Cut(kv, "=")
532						if !ok {
533							return fmt.Errorf("--set requires key=value format, got: %s", kv)
534						}
535						if k == "closing_commit_sha" {
536							normalizedCommitSHA, err := f.resolveClosingCommitSHA(v)
537							if err != nil {
538								return err
539							}
540							v = normalizedCommitSHA
541						}
542						setFlags = append(setFlags, k+"="+v)
543					}
544				}
545	
546				statusValue, _ := cmd.Flags().GetString("status")
547				statusChanged := cmd.Flags().Changed("status")
548				statusOpts := beadTransitionOptionsFromSetFlags(statusValue, setFlags, "ddx bead update")
549	
550				applyUpdateFields := func(b *bead.Bead) error {
551					if v, _ := cmd.Flags().GetString("title"); cmd.Flags().Changed("title") {
552						b.Title = v
553					}
554					if v, _ := cmd.Flags().GetInt("priority"); cmd.Flags().Changed("priority") {
555						b.Priority = v
556					}
557					if v, _ := cmd.Flags().GetString("labels"); cmd.Flags().Changed("labels") {
558						if v == "" {
559							b.Labels = []string{}
560						} else {
561							b.Labels = strings.Split(v, ",")
562						}
563					}
564					if v, _ := cmd.Flags().GetString("acceptance"); cmd.Flags().Changed("acceptance") {
565						b.Acceptance = v
566					}
567					if v, _ := cmd.Flags().GetString("assignee"); cmd.Flags().Changed("assignee") {
568						b.Owner = v
569					}
570					if v, _ := cmd.Flags().GetString("parent"); cmd.Flags().Changed("parent") {
571						b.Parent = v
572					}
573					if v, _ := cmd.Flags().GetString("description"); cmd.Flags().Changed("description") {
574						b.Description = v
575					}
576					if v, _ := cmd.Flags().GetString("notes"); cmd.Flags().Changed("notes") {
577						b.Notes = v
578					}
579					if len(setFlags) > 0 {
580						if b.Extra == nil {
581							b.Extra = make(map[string]any)
582						}
583						for _, kv := range setFlags {
584							k, v, ok := strings.Cut(kv, "=")
585							if !ok {
586								continue
587							}
588							// Route known field names to struct fields
589							switch k {
590							case "parent":
591								b.Parent = v
592							case "description":
593								b.Description = v
594							case "notes":
595								b.Notes = v
596							case "acceptance":
597								b.Acceptance = v
598							case "issue_type":
599								b.IssueType = v
600							default:
