1112	func (f *CommandFactory) resolveNeedsHumanBead(id, action, note string, children []string) error {
1113		action = strings.TrimSpace(action)
1114		note = strings.TrimSpace(note)
1115		if note == "" {
1116			return fmt.Errorf("--note is required")
1117		}
1118		s := f.beadStore()
1119		switch action {
1120		case "retry":
1121			if err := s.UpdateWithLifecycleStatus(id, bead.StatusOpen, bead.LifecycleTransitionOptions{
1122				Reason: "human resolve retry",
1123				Actor:  resolveClaimAssignee(),
1124				Source: "ddx bead human resolve",
1125			}, func(b *bead.Bead) error {
1126				// Migration-only cleanup: removes LabelNeedsHuman from legacy rows;
1127				// new rows carry status=proposed rather than this label.
1128				removeBeadLabel(b, bead.LabelNeedsHuman)
1129				bead.SetNeedsHumanMeta(b, bead.NeedsHumanMeta{})
1130				return nil
1131			}); err != nil {
1132				return err
1133			}
1134			if err := appendNeedsHumanResolutionEvent(s, id, action, note, nil); err != nil {
1135				return err
1136			}
1137		case "split":
1138			children = normalizeChildIDs(children)
1139			if len(children) == 0 {
1140				return fmt.Errorf("--children is required when --action split")
1141			}
1142			if err := validateSplitChildren(s, id, children); err != nil {
1143				return err
1144			}
1145			for _, childID := range children {
1146				if err := s.DepAdd(id, childID); err != nil {
1147					return err
1148				}
1149			}
1150			if err := s.UpdateWithLifecycleStatus(id, bead.StatusOpen, bead.LifecycleTransitionOptions{
1151				Reason: "human resolve split",
1152				Actor:  resolveClaimAssignee(),
1153				Source: "ddx bead human resolve",
1154			}, func(b *bead.Bead) error {
1155				// Migration-only cleanup: removes LabelNeedsHuman from legacy rows;
1156				// new rows carry status=proposed rather than this label.
1157				removeBeadLabel(b, bead.LabelNeedsHuman)
1158				bead.SetNeedsHumanMeta(b, bead.NeedsHumanMeta{})
1159				return nil
1160			}); err != nil {
1161				return err
1162			}
1163			if err := appendNeedsHumanResolutionEvent(s, id, action, note, children); err != nil {
1164				return err
1165			}
1166		case "obsolete":
1167			if err := appendNeedsHumanResolutionEvent(s, id, action, note, nil); err != nil {
1168				return err
1169			}
1170			if err := s.Close(id); err != nil {
1171				return err
1172			}
1173		case "defer":
1174			if err := appendNeedsHumanResolutionEvent(s, id, action, note, nil); err != nil {
1175				return err
1176			}
1177		default:
1178			return fmt.Errorf("unknown --action %q (valid: retry, split, obsolete, defer)", action)
1179		}
1180		if _, err := f.beadAutoCommit("human resolve " + id); err != nil {
1181			return err
1182		}
1183		return nil
1184	}
