1186	func needsHumanRow(b bead.Bead) beadNeedsHumanRow {
1187		meta := bead.GetNeedsHumanMeta(b)
1188		return beadNeedsHumanRow{
1189			ID:              b.ID,
1190			Priority:        b.Priority,
1191			Title:           b.Title,
1192			Reason:          meta.Reason,
1193			Since:           meta.Since,
1194			Source:          meta.Source,
1195			SuggestedAction: meta.SuggestedAction,
