1598	func gitStageBlob(ctx context.Context, repoRoot string, stage int, path string) ([]byte, error) {
1599		spec := fmt.Sprintf(":%d:%s", stage, path)
1600		out, err := gitpkg.Command(ctx, repoRoot, "show", spec).Output()
1601		if err != nil {
1602			return nil, fmt.Errorf("bead merge: read Git stage %d for %s: %w", stage, path, err)
1603		}
1604		return out, nil
1605	}
