1607	// newBeadCooldownCommand wires `ddx bead cooldown show|clear <id>`.
1608	//
1609	// `cooldown show` prints the bead's current work cooldown fields
1610	// (retry-after, last-status, last-detail) in human or JSON form. `cooldown
1611	// clear` removes those three fields so the bead becomes execution-eligible
1612	// again at the next loop pass. This is the first-class operator-facing
1613	// surface for the underlying `execute-loop-retry-after` Extra key — the
1614	// `ddx bead update --set/--unset execute-loop-retry-after=...` workflow
1615	// continues to work as a power-user fallback, but operators should reach
1616	// for `cooldown clear` for the common case.
1617	func (f *CommandFactory) newBeadCooldownCommand() *cobra.Command {
1618		cmd := &cobra.Command{
1619			Use:   "cooldown",
1620			Short: "Inspect and clear work cooldowns",
1621			Long: `Inspect and clear the work cooldown that parks a bead from
1622	re-execution. Cooldowns are set automatically by the loop in three cases:
1623	
1624	  * no_changes with a vague rationale (short retry, default 6h)
1625	  * push_failed (long park, 365d, requires operator action)
1626	  * declined_needs_decomposition (long park, 365d, requires decomposition)
1627	
1628	Use this command instead of editing the magic Extra key directly:
1629	
1630	  ddx bead cooldown show <bead-id>     # show retry-after, last-status, last-detail
1631	  ddx bead cooldown clear <bead-id>    # remove cooldown so the bead re-enters the queue
1632	`,
1633			Run: func(cmd *cobra.Command, args []string) { _ = cmd.Help() },
1634		}
1635	
1636		showCmd := &cobra.Command{
1637			Use:   "show <id>",
1638			Short: "Show the work cooldown fields for a bead",
1639			Args:  cobra.ExactArgs(1),
1640			RunE: func(cmd *cobra.Command, args []string) error {
1641				s := f.beadStore()
1642				b, err := s.Get(args[0])
1643				if err != nil {
1644					return err
1645				}
1646				retry, _ := b.Extra["execute-loop-retry-after"].(string)
1647				lastStatus, _ := b.Extra["execute-loop-last-status"].(string)
1648				lastDetail, _ := b.Extra["execute-loop-last-detail"].(string)
1649	
1650				asJSON, _ := cmd.Flags().GetBool("json")
1651				if asJSON {
1652					enc := json.NewEncoder(cmd.OutOrStdout())
1653					enc.SetIndent("", "  ")
1654					return enc.Encode(struct {
1655						BeadID      string `json:"bead_id"`
1656						RetryAfter  string `json:"retry_after,omitempty"`
1657						LastStatus  string `json:"last_status,omitempty"`
1658						LastDetail  string `json:"last_detail,omitempty"`
1659						ParkedUntil string `json:"parked_until,omitempty"`
1660					}{BeadID: b.ID, RetryAfter: retry, LastStatus: lastStatus, LastDetail: lastDetail, ParkedUntil: retry})
1661				}
1662	
1663				if retry == "" {
1664					fmt.Fprintf(cmd.OutOrStdout(), "%s: no cooldown set\n", b.ID)
1665					return nil
1666				}
1667				fmt.Fprintf(cmd.OutOrStdout(), "bead:        %s\n", b.ID)
1668				fmt.Fprintf(cmd.OutOrStdout(), "retry_after: %s\n", retry)
1669				if lastStatus != "" {
1670					fmt.Fprintf(cmd.OutOrStdout(), "last_status: %s\n", lastStatus)
1671				}
1672				if lastDetail != "" {
