1681		clearCmd := &cobra.Command{
1682			Use:   "clear <id>",
1683			Short: "Clear the work cooldown for a bead",
1684			Args:  cobra.ExactArgs(1),
1685			RunE: func(cmd *cobra.Command, args []string) error {
1686				s := f.beadStore()
