1691					}
1692					for _, key := range []string{
1693						"execute-loop-retry-after",
1694						"execute-loop-last-status",
1695						"execute-loop-last-detail",
1696					} {
1697						if _, ok := b.Extra[key]; ok {
1698							delete(b.Extra, key)
