26	func (f *CommandFactory) newAcRunCommand() *cobra.Command {
27		var only string
28		var fromRev string
29		cmd := &cobra.Command{
30			Use:   "run <bead-id>",
31			Short: "Run all applicable checks against the current worktree",
32			Long: `Run every check in .ddx/checks/*.yaml whose applies_to filter matches the
33	named bead and the changed paths between DIFF_BASE and HEAD. Each check
34	runs in parallel and writes its result file under .ddx/executions/ac-<ts>/.
35	
36	Exits 1 if any check returns block or error.`,
37			Args: cobra.ExactArgs(1),
38			RunE: func(cmd *cobra.Command, args []string) error {
39				beadID := args[0]
40				projectRoot := f.WorkingDir
41	
42				b, err := loadBead(projectRoot, beadID)
43				if err != nil {
44					return fmt.Errorf("load bead: %w", err)
45				}
46	
47				diffHead, err := gitRevParse(projectRoot, "HEAD")
48				if err != nil {
49					return fmt.Errorf("resolve HEAD: %w", err)
50				}
51				diffBase := fromRev
52				if diffBase == "" {
53					diffBase = beadBaseRev(b)
54				}
55				if diffBase == "" {
56					diffBase, _ = gitMergeBase(projectRoot, "HEAD", "main")
57				}
58				if diffBase == "" {
59					diffBase = diffHead // empty diff fallback
60				}
61	
62				changed, err := gitChangedPaths(projectRoot, diffBase, diffHead)
63				if err != nil {
64					return fmt.Errorf("diff paths: %w", err)
65				}
66	
67				all, err := checks.LoadDir(filepath.Join(projectRoot, ".ddx", "checks"))
68				if err != nil {
69					return err
70				}
71				if only != "" {
72					all = filterByName(all, only)
73					if len(all) == 0 {
74						return fmt.Errorf("no check named %q", only)
75					}
76				}
77	
78				runID := newRunID()
79				evidenceDir := filepath.Join(projectRoot, ".ddx", "executions", "ac-"+runID)
80				ictx := checks.InvocationContext{
81					BeadID:       beadID,
82					DiffBase:     diffBase,
83					DiffHead:     diffHead,
84					ProjectRoot:  projectRoot,
85					EvidenceDir:  evidenceDir,
86					RunID:        runID,
87					BeadLabels:   b.Labels,
88					ChangedPaths: changed,
89				}
90	
91				results, err := checks.Run(cmd.Context(), all, ictx)
92				if err != nil {
93					return err
94				}
95	
96				out := cmd.OutOrStdout()
97				fmt.Fprintf(out, "ac run %s (bead=%s base=%s head=%s checks=%d evidence=%s)\n",
98					runID, beadID, shortSHA(diffBase), shortSHA(diffHead), len(results), evidenceDir)
99				anyBad := false
100				for _, r := range results {
101					marker := "PASS"
102					switch r.Status {
103					case checks.StatusBlock:
104						marker = "BLOCK"
105						anyBad = true
106					case checks.StatusError:
107						marker = "ERROR"
108						anyBad = true
109					}
110					fmt.Fprintf(out, "  [%s] %s — %s\n", marker, r.Name, r.Message)
111					for _, v := range r.Violations {
112						loc := v.File
113						if v.Line > 0 {
114							loc = fmt.Sprintf("%s:%d", v.File, v.Line)
115						}
116						fmt.Fprintf(out, "      %s %s %s\n", loc, v.Symbol, v.Detail)
117					}
118				}
119				if anyBad {
120					return fmt.Errorf("one or more checks reported block/error")
121				}
122				return nil
123			},
124		}
125		cmd.Flags().StringVar(&only, "check", "", "Run only the named check")
126		cmd.Flags().StringVar(&fromRev, "from", "", "Override DIFF_BASE (defaults to bead base_rev or merge-base with main)")
127		return cmd
128	}
