135	func beadBaseRev(b *bead.Bead) string {
136		if b == nil || b.Extra == nil {
137			return ""
138		}
139		for _, k := range []string{"base_rev", "base-rev", "baseRev"} {
140			if v, ok := b.Extra[k]; ok {
141				if s, ok := v.(string); ok && s != "" {
142					return s
143				}
144			}
145		}
146		return ""
147	}
148	
149	func filterByName(all []checks.Check, name string) []checks.Check {
150		out := make([]checks.Check, 0, 1)
151		for _, c := range all {
152			if c.Name == name {
153				out = append(out, c)
154			}
155		}
156		return out
157	}
158	
159	func gitRevParse(dir, ref string) (string, error) {
160		out, err := exec.Command("git", "-C", dir, "rev-parse", ref).Output()
161		if err != nil {
162			return "", err
163		}
164		return strings.TrimSpace(string(out)), nil
165	}
166	
167	func gitMergeBase(dir, a, b string) (string, error) {
168		out, err := exec.Command("git", "-C", dir, "merge-base", a, b).Output()
169		if err != nil {
170			return "", err
171		}
172		return strings.TrimSpace(string(out)), nil
173	}
174	
175	func gitChangedPaths(dir, base, head string) ([]string, error) {
176		if base == "" || base == head {
177			return nil, nil
178		}
179		out, err := exec.Command("git", "-C", dir, "diff", "--name-only", base, head).Output()
180		if err != nil {
181			return nil, err
182		}
183		lines := strings.Split(strings.TrimSpace(string(out)), "\n")
184		paths := make([]string, 0, len(lines))
185		for _, l := range lines {
186			l = strings.TrimSpace(l)
187			if l != "" {
188				paths = append(paths, l)
189			}
190		}
191		return paths, nil
192	}
193	
194	func newRunID() string {
195		var b [4]byte
196		_, _ = rand.Read(b[:])
197		return time.Now().UTC().Format("20060102T150405") + "-" + hex.EncodeToString(b[:])
198	}
199	
200	func shortSHA(s string) string {
201		if len(s) >= 8 {
202			return s[:8]
203		}
204		return s
205	}
