125	func (f *CommandFactory) resolveCommitSHA(commitSHA string) (string, error) {
126		if commitSHA == "" {
127			return "", nil
128		}
129	
130		ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
131		defer cancel()
132	
133		repoDir := f.WorkingDir
134		if repoDir == "" {
135			repoDir = "."
136		}
137	
138		if isFullCommitSHA(commitSHA) && !gitpkg.IsRepository(repoDir) {
139			return commitSHA, nil
140		}
141	
142		cmd := gitpkg.Command(ctx, repoDir, "rev-parse", "--verify", commitSHA+"^{commit}")
143		out, err := cmd.Output()
144		if err != nil {
145			return "", fmt.Errorf("git rev-parse %s: %w", commitSHA, err)
146		}
147		return strings.TrimSpace(string(out)), nil
148	}
149	
150	func isFullCommitSHA(commitSHA string) bool {
151		if len(commitSHA) != 40 {
152			return false
153		}
154		for i := 0; i < len(commitSHA); i++ {
155			c := commitSHA[i]
156			if c >= '0' && c <= '9' {
157				continue
158			}
159			if c >= 'a' && c <= 'f' {
160				continue
161			}
162			if c >= 'A' && c <= 'F' {
163				continue
164			}
165			return false
166		}
167		return true
168	}
169	
170	func (f *CommandFactory) resolveClosingCommitSHA(commitSHA string) (string, error) {
171		normalizedCommitSHA, err := f.resolveCommitSHA(commitSHA)
172		if err != nil {
173			return "", fmt.Errorf("invalid closing_commit_sha %q: %w", commitSHA, err)
174		}
175		if normalizedCommitSHA == "" {
176			return "", fmt.Errorf("invalid closing_commit_sha %q: empty value", commitSHA)
177		}
178		return normalizedCommitSHA, nil
179	}
