181	// commitIsMetadataOnlyTrackerBackfill reports whether the given commit changed
182	// only bead tracker state. Closing provenance is suppressed only for pure
183	// tracker backfills that touch .ddx/beads.jsonl and nothing else.
184	func (f *CommandFactory) commitIsMetadataOnlyTrackerBackfill(commitSHA string) bool {
185		if commitSHA == "" {
186			return false
187		}
188	
189		ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
190		defer cancel()
191	
192		cmd := gitpkg.Command(ctx, f.WorkingDir, "show", "--pretty=format:", "--name-only", commitSHA)
193		out, err := cmd.Output()
194		if err != nil {
195			return false
196		}
197	
198		for _, line := range strings.Split(string(out), "\n") {
199			path := strings.TrimSpace(line)
200			if path == "" {
201				continue
202			}
203			if path != ".ddx/beads.jsonl" {
204				return false
205			}
206		}
207	
208		return true
209	}
