641		cmd.Flags().String("title", "", "New title")
642		cmd.Flags().String("status", "", "New lifecycle status (validated transition)")
643		cmd.Flags().Int("priority", 0, "New priority")
644		cmd.Flags().String("labels", "", "New labels (comma-separated)")
