691	func beadTransitionOptionsFromSetFlags(status string, setFlags []string, source string) bead.LifecycleTransitionOptions {
692		opts := bead.LifecycleTransitionOptions{
693			Reason: "set lifecycle status",
694			Source: source,
695		}
696		if status == bead.StatusBlocked {
