781	func (f *CommandFactory) newBeadCloseCommand() *cobra.Command {
782		cmd := &cobra.Command{
783			Use:   "close <id>",
784			Short: "Close a bead",
785			Args:  cobra.ExactArgs(1),
786			RunE: func(cmd *cobra.Command, args []string) error {
787				if err := f.checkLifecycleMigrationGate(cmd); err != nil {
788					return err
789				}
790				s := f.beadStore()
791				sessionID, _ := cmd.Flags().GetString("session")
792				commitSHA, _ := cmd.Flags().GetString("commit")
793	
794				if commitSHA != "" {
795					normalizedCommitSHA, err := f.resolveCommitSHA(commitSHA)
796					if err != nil {
797						return err
798					}
799					commitSHA = normalizedCommitSHA
800				}
801	
802				target, err := s.Get(args[0])
803				if err != nil {
804					return err
805				}
806				// CloseWithEvidence runs the closure gate (ddx-e30e60a9); manual
807				// operator closes without evidence are intentionally a separate
808				// path. When --session and --commit are both unset, we are in
809				// manual-administration territory — use the ungated Store.Close
810				// so the gate doesn't reject legitimate tracker admin.
811				if sessionID == "" && commitSHA == "" {
812					if err := s.Close(args[0]); err != nil {
813						return err
814					}
815				} else if err := s.CloseWithEvidence(args[0], sessionID, commitSHA); err != nil {
816					return err
817				}
818	
819				landedSHA, err := f.beadAutoCommitIncludingStaged("close " + args[0])
820				if err != nil {
821					return err
822				}
823				if commitSHA == "" && landedSHA != "" {
824					if f.commitIsMetadataOnlyTrackerBackfill(landedSHA) {
825						if isReviewCloseBead(target) {
826							// Tracker-only review-finding closes must not retain any prior
827							// replay boundary. The close commit itself is the metadata-only
828							// backfill, so clear stale closing provenance instead of
829							// preserving an unrelated implementation SHA.
830							if err := s.Update(args[0], func(b *bead.Bead) {
831								if b.Extra == nil {
832									return
833								}
834								delete(b.Extra, "closing_commit_sha")
835							}); err != nil {
836								return err
837							}
838							followupSHA, err := f.beadAutoCommit("close " + args[0])
839							if err != nil {
840								return err
841							}
842							if followupSHA == "" {
843								return fmt.Errorf("close %s: failed to auto-commit closing provenance", args[0])
844							}
845						}
846					} else {
847						// Only stamp closing provenance when the close commit includes
848						// real implementation work. Pure tracker backfills should not
849						// advertise a replay boundary that points at metadata-only
850						// provenance.
851						if err := s.Update(args[0], func(b *bead.Bead) {
852							if b.Extra == nil {
853								b.Extra = make(map[string]any)
854							}
855							b.Extra["closing_commit_sha"] = landedSHA
856						}); err != nil {
857							return err
858						}
859						followupSHA, err := f.beadAutoCommit("close " + args[0])
860						if err != nil {
861							return err
862						}
863						if followupSHA == "" {
864							return fmt.Errorf("close %s: failed to auto-commit closing provenance", args[0])
865						}
866					}
867				}
868				return nil
869			},
870		}
871		cmd.Flags().String("session", "", "Agent session ID that completed this bead")
872		cmd.Flags().String("commit", "", "Closing commit SHA (auto-detected if not provided)")
873		return cmd
874	}
