1228	func normalizeChildIDs(children []string) []string {
1229		var out []string
1230		seen := map[string]bool{}
1231		for _, raw := range children {
1232			for _, part := range strings.Split(raw, ",") {
1233				child := strings.TrimSpace(part)
1234				if child == "" || seen[child] {
1235					continue
1236				}
1237				seen[child] = true
1238				out = append(out, child)
1239			}
1240		}
1241		return out
1242	}
