1244	func validateSplitChildren(s *bead.Store, parentID string, children []string) error {
1245		if _, err := s.Get(parentID); err != nil {
1246			return err
1247		}
1248		for _, childID := range children {
1249			if childID == parentID {
1250				return fmt.Errorf("split child cannot be the parent bead: %s", childID)
1251			}
1252			if _, err := s.Get(childID); err != nil {
1253				return fmt.Errorf("split child %s: %w", childID, err)
1254			}
1255		}
1256		return nil
1257	}
