1531	func (f *CommandFactory) newBeadMergeCommand() *cobra.Command {
1532		cmd := &cobra.Command{
1533			Use:   "merge [path]",
1534			Short: "Resolve a Git conflict in .ddx/beads.jsonl",
1535			Long: `Resolve a Git conflict in .ddx/beads.jsonl using DDx tracker rules.
1536	
1537	This is the supported escape hatch when Git leaves the bead tracker in an
1538	unmerged state. It reads the base, ours, and theirs versions from the Git
1539	index stages (:1:, :2:, :3:), merges records by bead id, preserves append-only
1540	events and dependency edges, writes the resolved JSONL file, and reports any
1541	scalar fields that required deterministic conflict resolution.
1542	
1543	This command is not a general hand-edit workflow for bead tracker data.`,
1544			Args: cobra.MaximumNArgs(1),
1545			RunE: func(cmd *cobra.Command, args []string) error {
1546				path := filepath.Join(".ddx", "beads.jsonl")
1547				if len(args) > 0 {
1548					path = args[0]
1549				}
1550				workspaceRoot := f.beadWorkspaceRoot()
1551				if workspaceRoot == "" {
1552					workspaceRoot = f.WorkingDir
1553				}
1554				repoRoot := gitpkg.FindProjectRoot(workspaceRoot)
1555				relPath, err := filepath.Rel(repoRoot, filepath.Join(workspaceRoot, path))
1556				if err != nil || strings.HasPrefix(relPath, ".."+string(filepath.Separator)) || relPath == ".." {
1557					relPath = filepath.ToSlash(path)
1558				}
1559				relPath = filepath.ToSlash(filepath.Clean(relPath))
1560	
1561				base, err := gitStageBlob(cmd.Context(), repoRoot, 1, relPath)
1562				if err != nil {
1563					return err
1564				}
1565				ours, err := gitStageBlob(cmd.Context(), repoRoot, 2, relPath)
1566				if err != nil {
1567					return err
1568				}
1569				theirs, err := gitStageBlob(cmd.Context(), repoRoot, 3, relPath)
1570				if err != nil {
1571					return err
1572				}
1573	
1574				merged, report, err := bead.MergeTrackerConflictJSONL(base, ours, theirs)
1575				if err != nil {
1576					return err
1577				}
1578				outPath := filepath.Join(repoRoot, relPath)
1579				if err := os.MkdirAll(filepath.Dir(outPath), 0o755); err != nil {
1580					return fmt.Errorf("bead merge: mkdir: %w", err)
1581				}
1582				if err := os.WriteFile(outPath, merged, 0o644); err != nil {
1583					return fmt.Errorf("bead merge: write %s: %w", relPath, err)
1584				}
1585	
1586				fmt.Fprintf(cmd.OutOrStdout(), "Merged %s: %d records (%d ours-only, %d theirs-only, %d same-id merged)\n",
1587					relPath, report.TotalRecords, report.PreservedOurs, report.PreservedTheirs, report.MergedRecords)
1588				for _, conflict := range report.ScalarConflicts {
1589					fmt.Fprintf(cmd.OutOrStdout(), "Resolved scalar conflict: %s.%s chose %s (%s)\n",
1590						conflict.ID, conflict.Field, conflict.Choice, conflict.Reason)
1591				}
1592				return nil
1593			},
1594		}
1595		return cmd
1596	}
