1	// Package accheck mechanically verifies acceptance criteria against the
2	// working tree and diff. It is invoked by `ddx bead ac-check <id>` to produce
3	// a structured per-AC result file that both implementer (self-check
4	// pre-commit) and reviewer (gate ratification) consume.
5	//
6	// Per ddx-c739d7ec: the tool classifies each AC line into a kind
7	// (test-name | build-gate | negative | symbol | mechanical | prose) then
8	// resolves evidence mechanically. Prose AC always yields needs_judgment;
9	// never auto-pass, never auto-fail.
10	package accheck
11	
12	import (
13		"bufio"
14		"encoding/json"
15		"fmt"
16		"io"
17		"os/exec"
18		"path/filepath"
19		"regexp"
20		"strings"
21	)
22	
23	// SchemaVersion is bumped when the output JSON shape changes incompatibly.
24	const SchemaVersion = 1
25	
26	// Kind classifies an AC line by the evidence we know how to gather for it.
27	type Kind string
28	
29	const (
30		KindTestName   Kind = "test-name"
31		KindBuildGate  Kind = "build-gate"
32		KindNegative   Kind = "negative"
33		KindSymbol     Kind = "symbol"
34		KindMechanical Kind = "mechanical"
35		KindProse      Kind = "prose"
36	)
37	
38	// Result is the verdict on one AC item.
39	type Result string
40	
41	const (
42		ResultPass          Result = "pass"
43		ResultFail          Result = "fail"
44		ResultNeedsJudgment Result = "needs_judgment"
45		ResultError         Result = "error"
46	)
47	
48	// Item represents one parsed AC line with its classification.
49	type Item struct {
50		AC      int    // 1-based AC number
51		Text    string // original AC text (single line)
52		Kind    Kind   // classified kind
53		Name    string // extracted entity (test name, symbol, etc.); empty for prose
54		Alias   string // operator-declared substitution (e.g., TestFoo -> TestFoo/bar)
55	}
56	
57	// Output is the structured per-AC verification output written to
58	// .ddx/executions/<attempt-id>/ac-check.json.
59	type Output struct {
60		SchemaVersion int     `json:"schema_version"`
61		BeadID        string  `json:"bead_id"`
62		AttemptID     string  `json:"attempt_id,omitempty"`
63		Summary       Summary `json:"summary"`
64		Items         []Entry `json:"items"`
65	}
66	
67	// Summary aggregates counts across items.
68	type Summary struct {
69		Pass          int `json:"pass"`
70		Fail          int `json:"fail"`
71		NeedsJudgment int `json:"needs_judgment"`
72		Error         int `json:"error"`
73	}
74	
75	// Entry is one per-AC result in the structured output.
76	type Entry struct {
77		AC       int    `json:"ac"`
78		Kind     Kind   `json:"kind"`
79		Name     string `json:"name,omitempty"`
80		Result   Result `json:"result"`
81		Evidence string `json:"evidence"`
82	}
83	
84	// Context bundles the evaluator's inputs (working directory, diff range, package
85	// hint, optional ACAliases map). Tests inject this directly; the CLI builds it
86	// from flags.
87	type Context struct {
88		WorkingDir string
89		RevBase    string // typically "merge-base..HEAD" or a single ref; empty = no diff
90		Packages   []string
91		Aliases    map[int]string // AC number -> substitution (e.g. "TestFoo -> TestFoo/bar")
92	
93		// Test hooks. When non-nil, these replace the real implementations so tests
94		// can drive deterministic outcomes without invoking go/git subprocesses.
95		RunTest  func(name string, packages []string) (bool, string, error)
96		GitGrep  func(symbol string) (int, string, error) // returns hit count + sample
97		DiffHits func(symbol string) (int, error)         // hits in diff hunks specifically
98		FileInfo func(path string) (existsBefore, existsAfter bool, renamedFrom string)
99	}
100	
101	// ParseAcceptance splits the bead's acceptance text into numbered AC items.
102	// It recognises lines that start with "1.", "2.", etc., or "(a)", "(b)", etc.
103	// Continuation lines (no leading number) are appended to the prior item.
104	var itemHeadRE = regexp.MustCompile(`^\s*(?:(\d+)\.|\(([a-z])\))\s+(.*)$`)
105	
106	func ParseAcceptance(s string) []Item {
107		var items []Item
108		scanner := bufio.NewScanner(strings.NewReader(s))
109		scanner.Buffer(make([]byte, 64*1024), 1024*1024)
110		idx := 0
111		for scanner.Scan() {
112			line := scanner.Text()
113			if m := itemHeadRE.FindStringSubmatch(line); m != nil {
114				idx++
115				text := strings.TrimSpace(m[3])
116				items = append(items, Item{AC: idx, Text: text})
117			} else if len(items) > 0 {
118				trimmed := strings.TrimSpace(line)
119				if trimmed == "" {
120					continue
121				}
122				items[len(items)-1].Text += " " + trimmed
123			}
124		}
125		for i := range items {
126			items[i].Kind, items[i].Name = classify(items[i].Text)
127		}
128		return items
129	}
130	
131	// classify inspects an AC line and decides which mechanical evaluator should
132	// resolve it. Order matters: more-specific patterns first.
133	func classify(text string) (Kind, string) {
134		// 1. Backtick-symbol AC: `Foo.Bar()`, `pruneEvidenceDirs`, etc.
135		if m := backtickSymbolRE.FindStringSubmatch(text); m != nil {
136			// If the negative cue appears outside the backticks, this is a negative
137			// AC about the symbol, not a positive symbol AC.
138			if hasNegativeCue(text) {
139				return KindNegative, m[1]
140			}
141			return KindSymbol, m[1]
142		}
143	
144		// 2. Test-name AC: explicit Go test identifier.
145		if m := testNameRE.FindString(text); m != "" {
146			return KindTestName, m
147		}
148	
149		// 3. Build-gate AC: lefthook, go test ./..., pre-commit pass language.
150		if buildGateRE.MatchString(text) {
151			return KindBuildGate, ""
152		}
153	
154		// 4. Negative AC without backticks (still operates on a symbol name).
155		if hasNegativeCue(text) {
156			if name := extractNegativeSymbol(text); name != "" {
157				return KindNegative, name
158			}
159		}
160	
161		// 5. Mechanical AC: rename / doc / comment / file moves.
162		if mechanicalRE.MatchString(text) {
163			return KindMechanical, ""
164		}
165	
166		// 6. Default: prose.
167		return KindProse, ""
168	}
169	
170	var (
171		backtickSymbolRE = regexp.MustCompile("`([A-Za-z_][A-Za-z0-9_.]*(?:\\(\\))?)`")
172		testNameRE       = regexp.MustCompile(`\bTest[A-Z]\w*`)
173		buildGateRE      = regexp.MustCompile(`(?i)\b(lefthook|go test|go build|pre-commit|all pass|test.* green|tests? pass)\b`)
174		negativeCueRE    = regexp.MustCompile(`(?i)\b(no longer|does not|do not|never|removed?|cannot|must not|no calls? to|absence of|without|excluded from|stop tracking|untrack)\b`)
175		mechanicalRE     = regexp.MustCompile(`(?i)\b(rename|relocate(d|s)?|moved? to|file (exists?|present)|comment|docs?(\s+only)?|documentation|gitignore)\b`)
176		negSymbolWordRE  = regexp.MustCompile(`[A-Za-z_][A-Za-z0-9_.]{3,}`)
177	)
178	
179	func hasNegativeCue(s string) bool { return negativeCueRE.MatchString(s) }
180	
181	// extractNegativeSymbol pulls a plausible symbol token from a negative AC.
182	// Heuristic: longest identifier-like token after the negative cue.
183	func extractNegativeSymbol(text string) string {
184		loc := negativeCueRE.FindStringIndex(text)
185		if loc == nil {
186			return ""
187		}
188		tail := text[loc[1]:]
189		var best string
190		for _, m := range negSymbolWordRE.FindAllString(tail, -1) {
191			if len(m) > len(best) {
192				best = m
193			}
194		}
195		return best
196	}
197	
198	// Evaluate resolves each item to a result entry. ACAliases from ctx override
199	// the Name on a per-AC basis.
200	func Evaluate(items []Item, ctx Context) []Entry {
201		out := make([]Entry, 0, len(items))
202		for _, item := range items {
203			if alias, ok := ctx.Aliases[item.AC]; ok {
204				item.Alias = alias
205			}
206			out = append(out, evaluateOne(item, ctx))
207		}
208		return out
209	}
210	
211	func evaluateOne(item Item, ctx Context) Entry {
212		target := item.Name
213		if item.Alias != "" {
214			target = item.Alias
215		}
216		switch item.Kind {
217		case KindTestName:
218			return evalTestName(item, target, ctx)
219		case KindBuildGate:
220			return evalBuildGate(item, ctx)
221		case KindNegative:
222			return evalNegative(item, target, ctx)
223		case KindSymbol:
224			return evalSymbol(item, target, ctx)
225		case KindMechanical:
226			return evalMechanical(item, ctx)
227		default:
228			return Entry{
229				AC:       item.AC,
230				Kind:     KindProse,
231				Result:   ResultNeedsJudgment,
232				Evidence: "no mechanical anchor; defer to reviewer judgment",
233			}
234		}
235	}
236	
237	func evalTestName(item Item, target string, ctx Context) Entry {
238		e := Entry{AC: item.AC, Kind: KindTestName, Name: target}
239		if target == "" {
240			e.Result = ResultError
241			e.Evidence = "test-name AC could not resolve a test identifier"
242			return e
243		}
244		run := ctx.RunTest
245		if run == nil {
246			e.Result = ResultError
247			e.Evidence = "no test runner configured in context"
248			return e
249		}
250		ok, detail, err := run(target, ctx.Packages)
251		if err != nil {
252			e.Result = ResultError
253			e.Evidence = fmt.Sprintf("test runner error: %v", err)
254			return e
255		}
256		if ok {
257			e.Result = ResultPass
258			e.Evidence = fmt.Sprintf("test %s passed; %s", target, strings.TrimSpace(detail))
259			return e
260		}
261		e.Result = ResultFail
262		e.Evidence = fmt.Sprintf("test %s did not pass; %s", target, strings.TrimSpace(detail))
263		return e
264	}
265	
266	func evalBuildGate(item Item, ctx Context) Entry {
267		// Build gates are run separately (lefthook, go test ./...) by the orchestrator;
268		// here we report needs_judgment so the reviewer ratifies the orchestrator's
269		// exit code rather than the ac-check running them a second time.
270		return Entry{
271			AC:       item.AC,
272			Kind:     KindBuildGate,
273			Result:   ResultNeedsJudgment,
274			Evidence: "build/gate AC; orchestrator reports exit code separately",
275		}
276	}
277	
278	func evalNegative(item Item, target string, ctx Context) Entry {
279		e := Entry{AC: item.AC, Kind: KindNegative, Name: target}
280		if target == "" {
281			e.Result = ResultNeedsJudgment
282			e.Evidence = "negative AC without a resolvable symbol; defer to reviewer"
283			return e
284		}
285		grep := ctx.GitGrep
286		if grep == nil {
287			e.Result = ResultError
288			e.Evidence = "no git-grep hook configured in context"
289			return e
290		}
291		hits, sample, err := grep(target)
292		if err != nil {
293			e.Result = ResultError
294			e.Evidence = fmt.Sprintf("git-grep error: %v", err)
295			return e
296		}
297		if hits == 0 {
298			e.Result = ResultPass
299			e.Evidence = fmt.Sprintf("symbol %q has 0 hits in post-image; absence confirmed", target)
300			return e
301		}
302		e.Result = ResultFail
303		e.Evidence = fmt.Sprintf("symbol %q still has %d hits in post-image; AC requires absence (%s)", target, hits, strings.TrimSpace(sample))
304		return e
305	}
306	
307	func evalSymbol(item Item, target string, ctx Context) Entry {
308		e := Entry{AC: item.AC, Kind: KindSymbol, Name: target}
309		if target == "" {
310			e.Result = ResultError
311			e.Evidence = "symbol AC could not resolve an identifier"
312			return e
313		}
314		grep := ctx.GitGrep
315		if grep == nil {
316			e.Result = ResultError
317			e.Evidence = "no git-grep hook configured in context"
318			return e
319		}
320		hits, sample, err := grep(target)
321		if err != nil {
322			e.Result = ResultError
323			e.Evidence = fmt.Sprintf("git-grep error: %v", err)
324			return e
325		}
326		if hits == 0 {
327			e.Result = ResultFail
328			e.Evidence = fmt.Sprintf("symbol %q has 0 hits in post-image; AC requires its presence", target)
329			return e
330		}
331		diffHits := 0
332		if ctx.DiffHits != nil {
333			dh, derr := ctx.DiffHits(target)
334			if derr == nil {
335				diffHits = dh
336			}
337		}
338		if diffHits == 0 {
339			e.Result = ResultFail
340			e.Evidence = fmt.Sprintf("symbol %q exists (%d hits) but does NOT appear in diff; AC asks for an added/touched change", target, hits)
341			return e
342		}
343		e.Result = ResultPass
344		e.Evidence = fmt.Sprintf("symbol %q present with %d hits; diff touches %d (%s)", target, hits, diffHits, strings.TrimSpace(sample))
345		return e
346	}
347	
348	func evalMechanical(item Item, ctx Context) Entry {
349		// Mechanical ACs are file-presence / rename detection. Without a specific
350		// path, we yield needs_judgment so the reviewer adjudicates after seeing the
351		// diff name-status.
352		return Entry{
353			AC:       item.AC,
354			Kind:     KindMechanical,
355			Result:   ResultNeedsJudgment,
356			Evidence: "mechanical AC; reviewer adjudicates against diff name-status",
357		}
358	}
359	
360	// Aggregate builds the final Output from items and entries.
361	func Aggregate(beadID, attemptID string, entries []Entry) Output {
362		out := Output{
363			SchemaVersion: SchemaVersion,
364			BeadID:        beadID,
365			AttemptID:     attemptID,
366			Items:         entries,
367		}
368		for _, e := range entries {
369			switch e.Result {
370			case ResultPass:
371				out.Summary.Pass++
372			case ResultFail:
373				out.Summary.Fail++
374			case ResultNeedsJudgment:
375				out.Summary.NeedsJudgment++
376			case ResultError:
377				out.Summary.Error++
378			}
379		}
380		return out
381	}
382	
383	// MarshalJSON writes the Output as indented JSON.
384	func (o Output) MarshalJSON() ([]byte, error) {
385		type alias Output
386		return json.MarshalIndent(alias(o), "", "  ")
387	}
388	
389	// WriteHuman writes a human-readable table of the per-AC results.
390	func WriteHuman(w io.Writer, o Output) error {
391		fmt.Fprintf(w, "ac-check for %s", o.BeadID)
392		if o.AttemptID != "" {
393			fmt.Fprintf(w, " (attempt %s)", o.AttemptID)
394		}
395		fmt.Fprintln(w)
396		fmt.Fprintf(w, "summary: %d pass / %d fail / %d needs-judgment / %d error\n\n",
397			o.Summary.Pass, o.Summary.Fail, o.Summary.NeedsJudgment, o.Summary.Error)
398		for _, e := range o.Items {
399			fmt.Fprintf(w, "AC #%d  [%-13s]  %-14s  %s\n", e.AC, e.Kind, e.Result, truncate(e.Evidence, 100))
400		}
401		return nil
402	}
403	
404	func truncate(s string, n int) string {
405		if len(s) <= n {
406			return s
407		}
408		return s[:n-1] + "…"
409	}
