411	// DefaultGitGrep returns a GitGrep hook that runs `git grep -c <symbol>`
412	// inside workingDir. Empty string symbols are rejected.
413	func DefaultGitGrep(workingDir string) func(symbol string) (int, string, error) {
414		return func(symbol string) (int, string, error) {
415			if symbol == "" {
416				return 0, "", fmt.Errorf("empty symbol")
417			}
418			// Use a fixed-string match to avoid regex surprises.
419			cmd := exec.Command("git", "grep", "-c", "-F", "--", symbol)
420			cmd.Dir = workingDir
421			out, _ := cmd.Output() // exit=1 means no match; not an error here
422			hits := 0
423			sample := ""
424			for _, line := range strings.Split(strings.TrimSpace(string(out)), "\n") {
425				if line == "" {
426					continue
427				}
428				// format: "path/file.go:N"
429				parts := strings.SplitN(line, ":", 2)
430				if len(parts) == 2 {
431					// best-effort numeric
432					var n int
433					if _, err := fmt.Sscanf(parts[1], "%d", &n); err == nil {
434						hits += n
435					}
436				}
437				if sample == "" {
438					sample = line
439				}
440			}
441			return hits, sample, nil
442		}
443	}
444	
445	// DefaultDiffHits returns a DiffHits hook that counts occurrences of symbol in
446	// `git diff <base>..HEAD` output. base may be empty (no diff filter).
447	func DefaultDiffHits(workingDir, base string) func(symbol string) (int, error) {
448		return func(symbol string) (int, error) {
449			if symbol == "" {
450				return 0, nil
451			}
452			args := []string{"diff"}
453			if base != "" {
454				args = append(args, base)
455			}
456			cmd := exec.Command("git", args...)
457			cmd.Dir = workingDir
458			out, err := cmd.Output()
459			if err != nil {
460				return 0, err
461			}
462			return strings.Count(string(out), symbol), nil
463		}
464	}
465	
466	// DefaultRunTest returns a RunTest hook that invokes `go test -run '^<name>$'`
467	// against the given packages (or `./...` if none).
468	func DefaultRunTest(workingDir string) func(name string, packages []string) (bool, string, error) {
469		return func(name string, packages []string) (bool, string, error) {
470			args := []string{"test", "-run", "^" + regexp.QuoteMeta(name) + "$", "-count=1", "-short"}
471			if len(packages) == 0 {
472				args = append(args, "./...")
473			} else {
474				args = append(args, packages...)
475			}
476			cmd := exec.Command("go", args...)
477			cmd.Dir = filepath.Join(workingDir, "cli") // tests live under cli/
478			out, err := cmd.CombinedOutput()
479			text := strings.TrimSpace(string(out))
480			if err != nil {
481				return false, text, nil // test failure surfaces as ok=false, err nil
482			}
483			// `go test` exits 0 also when no tests match; detect that case.
484			if strings.Contains(text, "[no tests to run]") || strings.Contains(text, "no test files") {
485				return false, text + " (no matching test found)", nil
486			}
487			return true, text, nil
488		}
489	}
