130	func loadBead(projectRoot, id string) (*bead.Bead, error) {
131		store := bead.NewStore(filepath.Join(projectRoot, ".ddx"))
132		return store.Get(id)
133	}
134	
135	func beadBaseRev(b *bead.Bead) string {
136		if b == nil || b.Extra == nil {
137			return ""
138		}
139		for _, k := range []string{"base_rev", "base-rev", "baseRev"} {
140			if v, ok := b.Extra[k]; ok {
141				if s, ok := v.(string); ok && s != "" {
142					return s
143				}
144			}
145		}
146		return ""
147	}
