159	func gitRevParse(dir, ref string) (string, error) {
160		out, err := exec.Command("git", "-C", dir, "rev-parse", ref).Output()
161		if err != nil {
162			return "", err
163		}
164		return strings.TrimSpace(string(out)), nil
165	}
166	
167	func gitMergeBase(dir, a, b string) (string, error) {
168		out, err := exec.Command("git", "-C", dir, "merge-base", a, b).Output()
169		if err != nil {
170			return "", err
171		}
172		return strings.TrimSpace(string(out)), nil
173	}
174	
175	func gitChangedPaths(dir, base, head string) ([]string, error) {
176		if base == "" || base == head {
177			return nil, nil
178		}
179		out, err := exec.Command("git", "-C", dir, "diff", "--name-only", base, head).Output()
180		if err != nil {
181			return nil, err
182		}
183		lines := strings.Split(strings.TrimSpace(string(out)), "\n")
184		paths := make([]string, 0, len(lines))
185		for _, l := range lines {
186			l = strings.TrimSpace(l)
187			if l != "" {
