// ParseACAliases extracts an ACAliases map from a bead body (description or notes).
// Lines of the form "AC #<N>: <original> -> <alias>" are parsed into a map from AC
// number to the alias identifier.
func ParseACAliases(body string) map[int]string {
	out := map[int]string{}
	re := regexp.MustCompile(`(?m)^AC\s+#(\d+):\s+\S+\s+->\s+(\S+)`)
	for _, m := range re.FindAllStringSubmatch(body, -1) {
		n, err := strconv.Atoi(m[1])
		if err != nil {
			continue
		}
		out[n] = m[2]
	}
	return out
}

