package cmd

import (
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"strings"

	"github.com/DocumentDrivenDX/ddx/internal/bead/accheck"
	"github.com/spf13/cobra"
)

func (f *CommandFactory) newBeadACCheckCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "ac-check <id>",
		Short: "Mechanically verify acceptance criteria against the working tree",
		Long: `Classify and resolve each AC item in the bead's acceptance field.

For each item ac-check:
  - test-name AC: runs go test -run '^<name>$'
  - build/gate AC: defers to orchestrator (needs_judgment)
  - negative AC: git-greps for residue symbols
  - symbol AC: git-greps + checks diff hunk touch
  - mechanical AC: defers to diff name-status (needs_judgment)
  - prose AC: always needs_judgment, never auto-pass or auto-fail

Output is written to .ddx/executions/<attempt-id>/ac-check.json when
DDX_ATTEMPT_ID is set, otherwise to a generated run directory. A
human-readable table is always printed to stdout.`,
		Args: cobra.ExactArgs(1),
		RunE: func(cmd *cobra.Command, args []string) error {
			beadID := args[0]
			projectRoot := f.WorkingDir

			b, err := loadBead(projectRoot, beadID)
			if err != nil {
				return fmt.Errorf("load bead: %w", err)
			}

			revRange, _ := cmd.Flags().GetString("rev-range")
			pkgs, _ := cmd.Flags().GetStringArray("package")
			asJSON, _ := cmd.Flags().GetBool("json")

			revBase := ""
			if revRange != "" {
				parts := strings.SplitN(revRange, "..", 2)
				if len(parts) == 2 {
					revBase = parts[0]
				} else {
					revBase = revRange
				}
			}
			if revBase == "" {
				if base := beadBaseRev(b); base != "" {
					revBase = base
				} else if mb, err2 := gitMergeBase(projectRoot, "HEAD", "main"); err2 == nil && mb != "" {
					revBase = mb
				}
			}

			// Collect ACAliases from description and notes.
			aliases := map[int]string{}
			for _, src := range []string{b.Description, b.Notes} {
				for k, v := range accheck.ParseACAliases(src) {
					aliases[k] = v
				}
			}

			ctx := accheck.Context{
				WorkingDir: projectRoot,
				RevBase:    revBase,
				Packages:   pkgs,
				Aliases:    aliases,
				RunTest:    accheck.DefaultRunTest(projectRoot),
				GitGrep:    accheck.DefaultGitGrep(projectRoot),
				DiffHits:   accheck.DefaultDiffHits(projectRoot, revBase),
			}

			items := accheck.ParseAcceptance(b.Acceptance)
			entries := accheck.Evaluate(items, ctx)

			// Resolve attempt ID: prefer DDX_ATTEMPT_ID env var, fall back to new run ID.
			attemptID := os.Getenv("DDX_ATTEMPT_ID")
			if attemptID == "" {
				attemptID = newRunID()
			}

			output := accheck.Aggregate(beadID, attemptID, entries)

			// Write JSON output file under .ddx/executions/<attempt-id>/ac-check.json
			execDir := filepath.Join(projectRoot, ".ddx", "executions", attemptID)
			if err := os.MkdirAll(execDir, 0o755); err != nil {
				return fmt.Errorf("mkdir executions dir: %w", err)
			}
			jsonPath := filepath.Join(execDir, "ac-check.json")
			data, err := json.MarshalIndent(output, "", "  ")
			if err != nil {
				return fmt.Errorf("marshal ac-check output: %w", err)
			}
			if err := os.WriteFile(jsonPath, data, 0o644); err != nil {
				return fmt.Errorf("write ac-check.json: %w", err)
			}

			w := cmd.OutOrStdout()
			if asJSON {
				_, err = w.Write(data)
				return err
			}
			return accheck.WriteHuman(w, output)
		},
	}

	cmd.Flags().String("rev-range", "", "Diff range for symbol/diff checks (e.g. merge-base..HEAD)")
	cmd.Flags().StringArray("package", nil, "Go package(s) to test (repeatable; default ./...)")
	cmd.Flags().Bool("json", false, "Print JSON output to stdout in addition to writing ac-check.json")

	return cmd
}

package accheck_test

import (
	"encoding/json"
	"fmt"
	"testing"

	"github.com/DocumentDrivenDX/ddx/internal/bead/accheck"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// stubRunTest returns a RunTest hook that passes for names in the pass set.
func stubRunTest(pass map[string]bool) func(string, []string) (bool, string, error) {
	return func(name string, _ []string) (bool, string, error) {
		if pass[name] {
			return true, fmt.Sprintf("--- PASS: %s (0.01s)", name), nil
		}
		return false, fmt.Sprintf("--- FAIL: %s (0.00s)\nFAIL\t[no test files]", name), nil
	}
}

// stubGitGrep returns a hook with preset hit counts per symbol.
func stubGitGrep(hits map[string]int) func(string) (int, string, error) {
	return func(symbol string) (int, string, error) {
		n := hits[symbol]
		sample := ""
		if n > 0 {
			sample = fmt.Sprintf("some/file.go:%d", n)
		}
		return n, sample, nil
	}
}

// stubDiffHits returns a hook with preset diff hit counts per symbol.
func stubDiffHits(hits map[string]int) func(string) (int, error) {
	return func(symbol string) (int, error) {
		return hits[symbol], nil
	}
}

func evalOne(t *testing.T, acText string, ctx accheck.Context) accheck.Entry {
	t.Helper()
	items := accheck.ParseAcceptance("1. " + acText)
	require.Len(t, items, 1)
	entries := accheck.Evaluate(items, ctx)
	require.Len(t, entries, 1)
	return entries[0]
}

// TestACCheck_TestNameAC_Passes verifies that a test-name AC passes when the
// named test runs successfully.
func TestACCheck_TestNameAC_Passes(t *testing.T) {
	ctx := accheck.Context{
		RunTest: stubRunTest(map[string]bool{"TestRetainDays": true}),
		GitGrep: stubGitGrep(nil),
	}
	entry := evalOne(t, "TestRetainDays passes", ctx)
	assert.Equal(t, accheck.KindTestName, entry.Kind)
	assert.Equal(t, accheck.ResultPass, entry.Result)
	assert.Contains(t, entry.Evidence, "TestRetainDays")
}

// TestACCheck_TestNameAC_Renamed_WithAlias verifies that when an ACAliases
// substitution is declared, the alias target is used instead of the original
// test name.
func TestACCheck_TestNameAC_Renamed_WithAlias(t *testing.T) {
	ctx := accheck.Context{
		Aliases: map[int]string{1: "TestFoo/bar"},
		RunTest: stubRunTest(map[string]bool{"TestFoo/bar": true}),
		GitGrep: stubGitGrep(nil),
	}
	entry := evalOne(t, "TestFoo passes", ctx)
	assert.Equal(t, accheck.KindTestName, entry.Kind)
	assert.Equal(t, accheck.ResultPass, entry.Result)
	assert.Equal(t, "TestFoo/bar", entry.Name)
}

// TestACCheck_TestNameAC_Missing_Fails verifies that a test-name AC fails when
// the named test does not run (no matching test found).
func TestACCheck_TestNameAC_Missing_Fails(t *testing.T) {
	ctx := accheck.Context{
		RunTest: stubRunTest(nil),
		GitGrep: stubGitGrep(nil),
	}
	entry := evalOne(t, "TestMissingFunc passes", ctx)
	assert.Equal(t, accheck.KindTestName, entry.Kind)
	assert.Equal(t, accheck.ResultFail, entry.Result)
}

// TestACCheck_NegativeAC_FlagsResidue verifies that a negative AC fails when
// the prohibited symbol is still present in the post-image.
func TestACCheck_NegativeAC_FlagsResidue(t *testing.T) {
	ctx := accheck.Context{
		GitGrep: stubGitGrep(map[string]int{"NetworkIO": 3}),
	}
	entry := evalOne(t, "no calls to NetworkIO in the post-image", ctx)
	assert.Equal(t, accheck.KindNegative, entry.Kind)
	assert.Equal(t, accheck.ResultFail, entry.Result)
	assert.Contains(t, entry.Evidence, "3 hits")
}

// TestACCheck_NegativeAC_AbsenceConfirmed_Passes verifies that a negative AC
// passes when the prohibited symbol has 0 hits in the post-image.
func TestACCheck_NegativeAC_AbsenceConfirmed_Passes(t *testing.T) {
	ctx := accheck.Context{
		GitGrep: stubGitGrep(nil),
	}
	entry := evalOne(t, "does not call LegacyNetworkSync anywhere", ctx)
	assert.Equal(t, accheck.KindNegative, entry.Kind)
	assert.Equal(t, accheck.ResultPass, entry.Result)
	assert.Contains(t, entry.Evidence, "0 hits")
}

// TestACCheck_SymbolAC_PresentInDiff_Passes verifies that a symbol AC passes
// when the symbol exists in the repo AND appears in diff hunks.
func TestACCheck_SymbolAC_PresentInDiff_Passes(t *testing.T) {
	ctx := accheck.Context{
		GitGrep:  stubGitGrep(map[string]int{"pruneEvidenceDirs": 2}),
		DiffHits: stubDiffHits(map[string]int{"pruneEvidenceDirs": 1}),
	}
	entry := evalOne(t, "implements `pruneEvidenceDirs` function", ctx)
	assert.Equal(t, accheck.KindSymbol, entry.Kind)
	assert.Equal(t, accheck.ResultPass, entry.Result)
}

// TestACCheck_SymbolAC_NotInDiff_Fails verifies that a symbol AC fails when
// the symbol exists in the repo but is NOT touched by the diff.
func TestACCheck_SymbolAC_NotInDiff_Fails(t *testing.T) {
	ctx := accheck.Context{
		GitGrep:  stubGitGrep(map[string]int{"pruneEvidenceDirs": 2}),
		DiffHits: stubDiffHits(nil),
	}
	entry := evalOne(t, "adds `pruneEvidenceDirs` function", ctx)
	assert.Equal(t, accheck.KindSymbol, entry.Kind)
	assert.Equal(t, accheck.ResultFail, entry.Result)
	assert.Contains(t, entry.Evidence, "does NOT appear in diff")
}

// TestACCheck_MechanicalAC_RenameDetection verifies that a mechanical AC
// (rename/file detection) yields needs_judgment so the reviewer adjudicates.
func TestACCheck_MechanicalAC_RenameDetection(t *testing.T) {
	ctx := accheck.Context{
		GitGrep: stubGitGrep(nil),
	}
	entry := evalOne(t, "rename OldPkg to NewPkg and update import paths", ctx)
	assert.Equal(t, accheck.KindMechanical, entry.Kind)
	assert.Equal(t, accheck.ResultNeedsJudgment, entry.Result)
}

// TestACCheck_ProseAC_NeedsJudgment_NeverAutoFail verifies that a prose AC
// never resolves to fail (only needs_judgment).
func TestACCheck_ProseAC_NeedsJudgment_NeverAutoFail(t *testing.T) {
	ctx := accheck.Context{
		GitGrep: stubGitGrep(nil),
	}
	entry := evalOne(t, "the implementation satisfies the reviewer's judgment about overall correctness", ctx)
	assert.Equal(t, accheck.KindProse, entry.Kind)
	assert.NotEqual(t, accheck.ResultFail, entry.Result)
	assert.Equal(t, accheck.ResultNeedsJudgment, entry.Result)
}

// TestACCheck_ProseAC_NeedsJudgment_NeverAutoPass verifies that a prose AC
// never resolves to pass (only needs_judgment).
func TestACCheck_ProseAC_NeedsJudgment_NeverAutoPass(t *testing.T) {
	ctx := accheck.Context{
		GitGrep: stubGitGrep(nil),
	}
	entry := evalOne(t, "overall quality is acceptable to the team", ctx)
	assert.Equal(t, accheck.KindProse, entry.Kind)
	assert.NotEqual(t, accheck.ResultPass, entry.Result)
	assert.Equal(t, accheck.ResultNeedsJudgment, entry.Result)
}

// TestACCheck_JSONOutput_SchemaVersion1 verifies that Aggregate produces output
// with schema_version=1.
func TestACCheck_JSONOutput_SchemaVersion1(t *testing.T) {
	ctx := accheck.Context{
		RunTest: stubRunTest(map[string]bool{"TestFoo": true}),
		GitGrep: stubGitGrep(nil),
	}
	items := accheck.ParseAcceptance("1. TestFoo passes")
	entries := accheck.Evaluate(items, ctx)
	output := accheck.Aggregate("ddx-test", "attempt-001", entries)

	assert.Equal(t, 1, output.SchemaVersion)
	assert.Equal(t, "ddx-test", output.BeadID)
	assert.Equal(t, "attempt-001", output.AttemptID)

	data, err := json.Marshal(output)
	require.NoError(t, err)

	var raw map[string]any
	require.NoError(t, json.Unmarshal(data, &raw))
	assert.Equal(t, float64(1), raw["schema_version"])
	assert.Equal(t, "ddx-test", raw["bead_id"])
}

// TestACCheck_RegressionFakeRetainDays replays the fake-work scenario from
// ddx-d22293ba where the implementer claimed to add a prune loop, counters,
// and 5 tests but the diff was only 5 lines setting a default value.
// ac-check must yield multiple fail results for the missing prune logic and tests.
func TestACCheck_RegressionFakeRetainDays(t *testing.T) {
	// The fake-work bead claimed these specific deliverables:
	acceptance := `1. TestRetainDaysPruneLoop passes
2. TestRetainDaysCounters passes
3. TestRetainDaysAgentLogs passes
4. TestRetainDaysWorkers passes
5. implements ` + "`PruneEvidenceByRetainDays`" + ` function
6. cd cli && go test ./... green`

	// Simulate the fake diff: only a default-value change, no new tests or symbols.
	// RunTest: no test passes (they weren't written).
	// GitGrep: PruneEvidenceByRetainDays exists 0 times (wasn't added).
	// DiffHits: no diff hits for any symbol.
	ctx := accheck.Context{
		RunTest:  stubRunTest(nil), // no test passes
		GitGrep:  stubGitGrep(nil),
		DiffHits: stubDiffHits(nil),
	}

	items := accheck.ParseAcceptance(acceptance)
	require.NotEmpty(t, items)

	entries := accheck.Evaluate(items, ctx)
	output := accheck.Aggregate("ddx-regression", "attempt-fake", entries)

	// Count failures: all test-name ACs and symbol AC should fail.
	failCount := 0
	for _, e := range output.Items {
		if e.Result == accheck.ResultFail {
			failCount++
		}
	}
	assert.GreaterOrEqual(t, failCount, 2,
		"fake-work diff must yield multiple fail results; got %d: %+v", failCount, output.Items)

	// Verify the symbol AC fails (PruneEvidenceByRetainDays not in diff).
	var symbolEntry *accheck.Entry
	for i, e := range output.Items {
		if e.Kind == accheck.KindSymbol {
			symbolEntry = &output.Items[i]
			break
		}
	}
	require.NotNil(t, symbolEntry, "expected a symbol AC for PruneEvidenceByRetainDays")
	assert.Equal(t, accheck.ResultFail, symbolEntry.Result)

	// The build-gate AC and prose AC should not be marked fail.
	for _, e := range output.Items {
		if e.Kind == accheck.KindBuildGate {
			assert.NotEqual(t, accheck.ResultFail, e.Result,
				"build-gate AC must not be auto-failed")
		}
	}
}
